{
  "name": "DenaliCare",
  "eligibility": {
    "age": 65,
    "income_limits": "For a single nursing home applicant in 2026: under $2,982 per month. Limits vary by marital status, program (Nursing Home Medicaid, HCBS Waivers, ABD Medicaid), and whether spouse is applying; no full household size table available in sources[1][2].",
    "asset_limits": "For a single applicant: $2,000 or less in countable assets. Countable assets typically include bank accounts, stocks, bonds (non-exempt); exemptions often include primary home (under equity limits), one vehicle, personal belongings, burial plots—specific exemptions vary and require state assessment[1][2].",
    "other_requirements": ["Alaska residency", "Nursing Facility Level of Care (NFLOC): need for full-time care based on evaluation of Activities of Daily Living (ADLs: mobility, bathing, dressing, eating, toileting) and Instrumental ADLs (IADLs: cleaning, cooking, shopping, paying bills), plus cognitive/behavioral issues[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Home and Community Based Services (HCBS) Waivers, Nursing Home care, Aged/Blind/Disabled (ABD) Medicaid long-term care services; specific services include those meeting NFLOC needs (e.g., personal care, home modifications if unable to live safely at home without); no fixed dollar amounts or hours specified[1][2].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: Alaska’s Resource for Integrated Eligibility Services (ARIES) Self-Service Portal", "Phone: Virtual Contact Center at 800-478-7778", "Mail/In-person: Submit Application for Services to Division of Public Assistance Office; contact Division of Senior and Disability Services or local Aging and Disability Resource Center (ADRC) for assistance[2]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Application for Services (GEN 50C)"],
    "documents": ["Proof of income, assets, residency, medical/functional need documentation for NFLOC assessment; specific list prepared via ADRC or DPA office[1][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Application via local Division of Public Assistance Offices or Aging and Disability Resource Centers (ADRCs), which may have regional processing differences; no specific wait time or provider variations detailed[2]",
    "offices_or_providers": ["Division of Public Assistance Offices", "Division of Senior and Disability Services offices", "Local Aging and Disability Resource Centers (ADRCs)"]
  },
  "official_source": "https://health.alaska.gov/ (Medicaid/DenaliCare section); ARIES portal for applications",
  "gotchas": ["DenaliCare for elderly long-term care is distinct from Denali KidCare (for children/pregnant women); financial eligibility varies by program and marital status—spousal impoverishment rules may apply; NFLOC required, not just age/low income; ways to qualify if over limits via planning, but consult experts[1][2][4]", "Processing/application may vary by specific program (e.g., HCBS vs. Nursing Home)"],
  "data_shape_notes": "Alaska residency and NFLOC functional test required; asset/income limits strict for singles but spousal protections exist; benefits via HCBS waivers or nursing home, assessed case-by-case; regional offices handle intake"
}

{
  "name": "Alzheimer's Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "Income and asset limits apply to the care recipient for CSRCP (specific dollar amounts not listed in sources; care manager determines based on reported monthly income of care recipient and spousal income).[1]",
    "asset_limits": "Asset limits apply to the care recipient for CSRCP (details on what counts/exempts not specified; includes wages, interest, dividends, net rental, Veteran's benefits, other recurring payments).[1]",
    "other_requirements": [
      "Care recipient must have a formal diagnosis of Alzheimer's disease or a related dementia (CSRCP).[1]",
      "Caregiver must be providing unpaid care (CSRCP and NFCSP).[1]",
      "For NFCSP: Care recipient 60+ or with Alzheimer's/related disorder (any age); or caregiver 60+ caring for adult child with disability; or grandparents/older relatives (55+) raising grandchildren.[1][2][3]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Respite care (adult day and in-home options, no cap on services); information and assistance; individual counseling, support groups, caregiver training; limited supplemental services (e.g., transportation, home modifications); educational materials, referrals for Alzheimer's/dementia.[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Fillable application form available at https://www.aoascc.org/Customer-Content/www/CMS/files/Caregiver_Support_Services_Application-Fillable_Combined_2025_05_19.pdf (Alaska Older Adults Senior Community Center, likely regional).[1]",
      "Contact local grantees of Alaska Department of Health and Social Services, Division of Senior and Disabilities Services (phone not specified in results; general senior line 800-478-7778).[1][3][5]",
      "Access via Home & Community Based Senior Grants website (http://dhss.alaska.gov/dsds/Pages/hcb/hcb.aspx).[2]"
    ],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": [
      "Caregiver Support Services Application (combined fillable form, covers CSRCP and NFCSP).[1]"
    ],
    "documents": [
      "Completed Application Form.[1]",
      "Proof of Diagnosis (physician’s note, medical record for Alzheimer’s/dementia, required for CSRCP).[1]",
      "Proof of Age (driver’s license, birth certificate, state ID if required).[1]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by Alaska Department of Health and Social Services, Division of Senior and Disabilities Services, and locally by grantees/providers (e.g., Alzheimer’s Disease Resource Agency in four locations; providers in 12 communities; AOASCC example).[1][3]",
    "offices_or_providers": [
      "Division of Senior and Disabilities Services grantees statewide.[3]",
      "Alzheimer’s Disease Resource Agency (four locations).[3]",
      "Providers in 12 communities.[3]"
    ]
  },
  "official_source": "http://dhss.alaska.gov/dsds/Pages/hcb/hcb.aspx",
  "gotchas": [
    "Two related programs: CSRCP (diagnosis + financial test required) vs. broader NFCSP (age-based, no diagnosis needed for general caregivers).[1]",
    "Financial eligibility only for CSRCP; NFCSP has no income test mentioned.[1][3]",
    "Proof of formal Alzheimer's/dementia diagnosis mandatory for CSRCP—people miss bringing physician documentation.[1]",
    "Services local via grantees, so availability varies by region despite statewide admin.[3]"
  ],
  "data_shape_notes": "Split into CSRCP (Alzheimer's-specific with income/asset tests) and NFCSP (broader family caregiver support); local grantees/providers handle delivery with regional variations; no fixed dollar/hour caps on respite."
}

{
  "name": "Alaska Legal Services Corporation (ALSC) Senior Legal Services",
  "eligibility": {
    "age": 60,
    "income_limits": "For seniors (60+), assistance may be provided without regard to income, with priority to those in social or economic need. General ALSC guideline is at or below 125% Federal Poverty Guidelines for Alaska: Household Size 1: Yearly $24,438 / Monthly $2,037 / Weekly $470; 2: $33,038 / $2,753 / $635; 3: $41,638 / $3,470 / $801; 4: $50,238 / $4,187 / $966; 5: $58,838 / $4,903 / $1,132; 6: $67,438 / $5,620 / $1,297; 7: $76,038 / $6,337 / $1,462; 8: $84,638 / $7,053 / $1,628; Each additional: $8,600 / $717 / $165. Incomes above may qualify in certain circumstances.",
    "asset_limits": "Assets are considered in eligibility screening (gross household assets requested in intake), based on federal poverty guidelines available upon request. Specific limits, countable assets, and exemptions not detailed publicly.",
    "other_requirements": ["Alaska resident", "Civil legal issue matching program priorities (e.g., income maintenance, housing, health care, advance directives, consumer issues)", "No conflicts of interest", "Case must align with office priorities"]
  },
  "benefits": {
    "type": "service",
    "value": "Legal assistance and advice; representation in court and administrative hearings; referrals; community education and training via clinics and outreach. Specific areas: Income maintenance (Alaska Senior Assistance Program, Social Security, SSI, Adult Public Assistance, Food Stamps); housing (landlord/tenant, public housing, assisted living, nursing homes); health care (Medicaid, Medicare, Long-Term Care, PCA); advance directives (power of attorney, living wills, testamentary wills); consumer issues (debt collection, predatory lending, deceptive practices, utility cutoffs). No fixed dollar amounts or hours specified.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://www.alsc-law.org/intake/ (Online Eligibility Interview)", "Phone: Toll-free statewide intake line 1-888-478-2572", "Mail/In-person: Paper application at nearest ALSC office (available in English, Samoan, Tagalog, Spanish, German, Russian)", "Legal clinics via https://www.alsc-law.org/ (check calendar)"],
    "processing_time": "Intake specialist contacts within two business days after online interview; full case acceptance varies due to resources and priorities.",
    "waitlist": "Not mentioned; limited resources mean not all cases accepted.",
    "forms": ["Online Eligibility Interview", "Paper Application for Services"],
    "documents": ["Gross household income details", "Asset information", "Phone number or email for contact", "Names of parties involved (for conflict check)", "Details of legal issue(s)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Alaska residents only",
    "regional_variations": "Priorities set by each office; contact nearest office for specifics. Services reach 147 communities statewide.",
    "offices_or_providers": ["Multiple offices statewide; nearest office for paper applications or questions"]
  },
  "official_source": "https://www.alsc-law.org/elder-advocacy/",
  "gotchas": ["Not all applicants accepted due to limited resources and case priorities; no guarantee from intake", "General ALSC exclusions: personal injury, accidents, wrongful death", "Income/assets screened preliminarily but fully evaluated later; seniors prioritized but income may still factor", "Conflicts of interest lead to referrals elsewhere", "Check legal clinics first for quicker help"],
  "data_shape_notes": "Seniors 60+ often income-disregarded with priority to need; office-specific priorities; no fixed asset details or wait times published; statewide but regionally prioritized cases"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; program is free advocacy service open to anyone with concerns[7][6][4]",
    "asset_limits": "No asset limits; no financial eligibility requirements[7][6]",
    "other_requirements": ["Residing in a long-term care facility (assisted living or nursing home) in Alaska, or age 60+ with issues related to residential circumstances in own home; made by or on behalf of the individual[7][4][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Identify, investigate, and resolve complaints; provide information on long-term services and supports; represent interests before agencies; seek remedies; regular facility visits and monitoring; educate on resident rights; support family/resident councils; community outreach and training[3][4][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-6393 (M-F 8:00 a.m. to 4:30 p.m. for intakes)[5]", "Website: https://akoltco.org (for information and volunteer opportunities, contact via site)[7]"],
    "processing_time": "Complaints investigated promptly; no formal application processing time as it's a direct service request[3][4]",
    "waitlist": null,
    "forms": ["No specific forms required; contact by phone to intake complaint[5]"],
    "documents": ["No documents needed; provide details of concern/complaint verbally or in writing[4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Alaska[5][7]",
    "regional_variations": "Volunteers provide services throughout state; statewide office with local volunteer support, no noted differences in services[1][7]",
    "offices_or_providers": ["Statewide Office of the Long Term Care Ombudsman, Alaska Mental Health Trust Authority[2][5][7]"]
  },
  "official_source": "https://akoltco.org",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy and complaint resolution; no eligibility barriers but must involve long-term care facility or home residential issues for 60+; families can contact on behalf of loved one; ombudsmen are confidential and independent[3][4][7]", "Program resolves complaints, does not provide direct care or funding[6]", "Authorized for at-home issues only related to 'residential circumstances' for 60+, not general home care[4][7]"],
  "data_shape_notes": "no income test; free advocacy service for complaints in LTC facilities or home residential issues for 60+; statewide with volunteers; not an entitlement program with applications or waitlists"
}
